#!/usr/bin/env bash
################################################################################
##                    通用工具函数库 (Unix)
##
## 提供日志记录、错误处理、权限检查等通用功能
## 使用方式：source "${SCRIPT_DIR}/lib/common-utils.sh"
##
## 编码: UTF-8 (LF) | 兼容: bash 4.0+
################################################################################

# 防止重复加载
if [ "${_COMMON_UTILS_LOADED:-0}" -eq 1 ]; then
  return 0 2>/dev/null || true
fi
_COMMON_UTILS_LOADED=1

# ============================================================================
# 日志函数
# ============================================================================

log() { echo "==> $*"; }

warn() { echo "⚠ WARNING: $*" >&2; }

success() { echo "✓ $*"; }

error() { echo "❌ 错误：$*" >&2; }

# ============================================================================
# 错误处理
# ============================================================================

err_trap() { echo "❌ 错误：第 $1 行发生错误" >&2; exit 1; }

# ============================================================================
# 权限与用户
# ============================================================================

# sudo 检查（仅在未被加载过时初始化）
if [ -z "${SUDO+x}" ]; then
  SUDO=${SUDO:-}
  if [ "$EUID" -ne 0 ]; then
    SUDO='sudo'
  fi
fi

# 目标用户和主目录（仅在被加载过时初始化）
if [ -z "${TARGET_USER+x}" ]; then
  TARGET_USER=${SUDO_USER:-$(whoami)}
  TARGET_HOME=$(eval echo "~${TARGET_USER}")
fi
